mapper.insert:
/** EvlIemDao.insert */
insert into uspt_evl_iem_nm
     (
	   evl_iem_id
	 , evl_table_id
	 , evl_div_cd
	 , evl_iem_nm
	 , evl_iem_cn
	 , allot_score
	 , evl_stdr_no
	 , sort_ordr_no
	 , creator_id
	 , created_dt
	 , updater_id
	 , updated_dt
) values (
	   #{evlIemId}
	 , #{evlTableId}
	 , #{evlDivCd}
	 , #{evlIemNm}
	 , #{evlIemCn}
	 , #{allotScore}
	 , #{evlStdrNo}
	 , #{sortOrdrNo}
	 , #{creatorId}
	 , #{createdDt}
	 , #{updaterId}
	 , #{updatedDt}
)

mapper.update:
	/** EvlIemDao.update */
	update uspt_evl_iem_nm
	   set
		   evl_div_cd                = #{evlDivCd}
		 , evl_iem_nm                = #{evlIemNm}
		 , evl_iem_cn                = #{evlIemCn}
		 , allot_score               = #{allotScore}
		 , evl_stdr_no               = #{evlStdrNo}
		 , sort_ordr_no              = #{sortOrdrNo}
		 , updater_id                = #{updaterId}
		 , updated_dt                = #{updatedDt}
	where 1=1
      and evl_iem_id 	= #{evlIemId}
	  and evl_table_id  = #{evlTableId}

mapper.delete:
	/** EvlIemDao.delete */
	delete from uspt_evl_iem_nm
	where 1=1
      and evl_iem_id 	= #{evlIemId}
	  and evl_table_id  = #{evlTableId}
